const records = {
  R1: {scenario_severity:1.09, tool_access_level:96.93, historical_fail_rate:2.14, coverage_gap:21.08},
  R2: {scenario_severity:8.57, tool_access_level:61.14, historical_fail_rate:41.12, coverage_gap:61.87},
  R3: {scenario_severity:4.77, tool_access_level:66.43, historical_fail_rate:6.88, coverage_gap:61.17},
  R4: {scenario_severity:1.16, tool_access_level:31.62, historical_fail_rate:25.81, coverage_gap:69.37},
};
const maxes = Object.fromEntries(Object.keys(records.R1).map(k => [k, Math.max(...Object.values(records).map(r => r[k]))]));
const weights = {scenario_severity:0.4, tool_access_level:0.3, historical_fail_rate:0.2, coverage_gap:0.1};
for (const [id,r] of Object.entries(records)) {
  let score = 0;
  const norm = {};
  for (const k of Object.keys(weights)) {
    norm[k] = r[k]/maxes[k];
    score += norm[k]*weights[k];
  }
  console.log(id, JSON.stringify({norm, score}));
}
console.log('maxes', maxes);
